import React, { useState } from 'react';
import { User } from 'lucide-react';
import Card from '../components/Card';
import { useClient } from '../contexts/ClientContext';

const Labs: React.FC = () => {
  const { selectedClient } = useClient();
  const [activeTab, setActiveTab] = useState<'data' | 'strategy' | 'content' | 'social'>('data');

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <h1 className="text-2xl font-bold text-gray-900 mb-8">Action Labs</h1>

      {!selectedClient ? (
        <Card>
          <div className="text-center py-12">
            <div className="w-16 h-16 mx-auto mb-4 bg-gray-100 rounded-full flex items-center justify-center">
              <User className="w-8 h-8 text-gray-400" />
            </div>
            <h3 className="text-lg font-medium text-gray-900 mb-2">
              Client Selection Required
            </h3>
            <p className="text-gray-600">
              Please select a client from the home page to access Action Labs features.
            </p>
          </div>
        </Card>
      ) : (
        <>
          {/* Tab Navigation */}
          <div className="border-b border-gray-200 mb-8">
            <nav className="-mb-px flex space-x-8">
              <button
                onClick={() => setActiveTab('data')}
                className={`py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'data'
                    ? 'border-primary-500 text-primary-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Data Entry
              </button>
              <button
                onClick={() => setActiveTab('strategy')}
                className={`py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'strategy'
                    ? 'border-primary-500 text-primary-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Strategy View
              </button>
              <button
                onClick={() => setActiveTab('content')}
                className={`py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'content'
                    ? 'border-primary-500 text-primary-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Content
              </button>
              <button
                onClick={() => setActiveTab('social')}
                className={`py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'social'
                    ? 'border-primary-500 text-primary-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Social Media
              </button>
            </nav>
          </div>

          {/* Tab Content */}
          <div className="space-y-6">
            {activeTab === 'data' && (
              <Card>
                <div className="text-center py-12">
                  <h3 className="text-lg font-medium text-gray-900 mb-2">
                    Data Entry
                  </h3>
                  <p className="text-gray-600">
                    Data entry features for {selectedClient.name} will be implemented here.
                  </p>
                </div>
              </Card>
            )}

            {activeTab === 'strategy' && (
              <Card>
                <div className="text-center py-12">
                  <h3 className="text-lg font-medium text-gray-900 mb-2">
                    Strategy View
                  </h3>
                  <p className="text-gray-600">
                    Strategy planning and analysis for {selectedClient.name}.
                  </p>
                </div>
              </Card>
            )}

            {activeTab === 'content' && (
              <Card>
                <div className="text-center py-12">
                  <h3 className="text-lg font-medium text-gray-900 mb-2">
                    Content Management
                  </h3>
                  <p className="text-gray-600">
                    Content creation and management tools for {selectedClient.name}.
                  </p>
                </div>
              </Card>
            )}

            {activeTab === 'social' && (
              <Card>
                <div className="text-center py-12">
                  <h3 className="text-lg font-medium text-gray-900 mb-2">
                    Social Media Management
                  </h3>
                  <p className="text-gray-600">
                    Social media tools and analytics for {selectedClient.name}.
                  </p>
                </div>
              </Card>
            )}
          </div>
        </>
      )}
    </div>
  );
};

export default Labs;
